class Solution:
    def partitionArray(self, nums, k):
        n = len(nums)
        if n % k != 0:
            return False
        groups = n // k
        from collections import Counter
        cnt = Counter(nums)
        for v in cnt.values():
            if v > groups:
                return False
        return True

