var partitionArray = function(nums, k) {
    const n = nums.length;
    if (n % k !== 0) return false;
    const g = n / k;
    const cnt = new Map();
    let mx = 0;
    for (const v of nums) {
        const c = (cnt.get(v) || 0) + 1;
        cnt.set(v, c);
        if (c > mx) mx = c;
    }
    return mx <= g;
};
